sql:
SELECT adjusted_close_price
FROM trading_data
WHERE trading_code = '1' AND date BETWEEN '2023-01-01' AND '2023-12-31';

SELECT date, trading_code, close_price
     FROM trading_data
     WHERE date = '0';

SELECT high_price, low_price
FROM trading_data
WHERE trading_code = '1' AND date = '1';

SELECT COUNT(date) AS trading_days_count
FROM trading_data
WHERE trading_code = 'AAPL';
